<script setup lang="ts">import{ref,onMounted}from'vue';import{addDaysToDateInput,toLocalDateInputValue}from'@/lib/local-date';import{fetchReservation,cancelReservation,fetchReservationSlots,rescheduleReservation}from'@/services/reservation';import type{Reservation,ReservationSlot}from'@/types/reservation';const props=defineProps<{reservationId:number}>(),reservation=ref<Reservation|null>(null),minimumDate=toLocalDateInputValue(),date=ref(addDaysToDateInput(minimumDate,1)),slots=ref<ReservationSlot[]>([]),errorMessage=ref('');async function load(){reservation.value=await fetchReservation(props.reservationId);const suggestedDate=addDaysToDateInput(reservation.value.reserveTime,1);date.value=suggestedDate<minimumDate?minimumDate:suggestedDate}async function cancel(){try{reservation.value=await cancelReservation(props.reservationId)}catch(e){errorMessage.value=e instanceof Error?e.message:'取消失败'}}async function findSlots(){if(reservation.value)slots.value=(await fetchReservationSlots(reservation.value.shop.id,date.value,reservation.value.peopleCount)).list}async function reschedule(slot:ReservationSlot){try{reservation.value=await rescheduleReservation(props.reservationId,slot.slotId,`${date.value} ${slot.startTime}`,'用户在线改期');slots.value=[]}catch(e){errorMessage.value=e instanceof Error?e.message:'改期失败'}}onMounted(()=>load().catch(e=>errorMessage.value=e.message))</script><template><section v-if="reservation" class="page-section"><div class="page-header"><div><p class="eyebrow">预订 {{reservation.reservationNo}}</p><h1>{{reservation.shop.name}}</h1><p>{{reservation.reserveTime}} · {{reservation.peopleCount}} 人 · {{reservation.statusText}}</p></div></div><p v-if="errorMessage" class="feedback is-error">{{errorMessage}}</p><div class="hero-actions"><button v-if="reservation.canCancel" class="secondary-button" @click="cancel">取消预订</button><template v-if="reservation.canReschedule"><input v-model="date" type="date" :min="minimumDate"><button class="secondary-button" @click="findSlots">查询改期时段</button></template></div><div class="tag-row"><button v-for="slot in slots" :key="slot.slotId" class="secondary-button" :disabled="!slot.available" @click="reschedule(slot)">{{slot.startTime}} · {{slot.confirmModeText}} · 余 {{slot.remainingCount}}</button></div><section class="content-card"><h2>变更时间线</h2><div class="review-list"><article v-for="item in reservation.timeline" :key="item.createdAt+item.actionType" class="review-card"><strong>{{item.actionText}}</strong><p>{{item.remark}}</p><span>{{item.createdAt}}</span></article></div></section></section></template>
